class Solution:
    def trailingZeroes(self, n: int) -> int:
        cnt = 0
        while n:
            n //= 5
            cnt += n
        return cnt

solutions.cpp:
class Solution {
public:
    int trailingZeroes(int n) {
        int cnt = 0;
        for (long long p = 5; p <= n; p *= 5) cnt += n / p;
        return cnt;
    }
};

